[
  {"start": true, "stop": false},
  {"start": false, "stop": false},
  {"start": false, "stop": true}
]

PROGRAM MAIN
VAR
    bStart       : BOOL;
    bStop        : BOOL;
    bOutput      : BOOL;
END_VAR

(* Eğitim örneği: sembolik girişlerle basit mühürleme mantığı. *)
IF bStop THEN
    bOutput := FALSE;
ELSIF bStart THEN
    bOutput := TRUE;
END_IF

END_PROGRAM
